patch:
--- a/comparator.v
+++ b/comparator.v
@@ -1,15 +1,15 @@
 module comp_8bit(
   input [7:0] a,
   input [7:0] b,
   output eq,
   output lt,
   output gt
 );
   assign eq = (a == b);
   assign lt = (a < b);
   assign gt = (a > b);
 endmodule

 module testbench;
   reg [7:0] val1, val2;
-  wire equal, less, greater;
-  comp_8bit cmp (.a(val1), .b(val2[3:0]), .eq(equal), .lt(less), .gt(greater));
+  wire equal, less, greater;
+  comp_8bit cmp (.a(val1), .b(val2), .eq(equal), .lt(less), .gt(greater));
 endmodule

before_code:
module comp_8bit(
  input [7:0] a,
  input [7:0] b,
  output eq,
  output lt,
  output gt
);
  assign eq = (a == b);
  assign lt = (a < b);
  assign gt = (a > b);
endmodule

module testbench;
  reg [7:0] val1, val2;
  wire equal, less, greater;
  comp_8bit cmp (.a(val1), .b(val2[3:0]), .eq(equal), .lt(less), .gt(greater));
endmodule

